1	import { defineStore } from 'pinia'
2	import { ref } from 'vue'
3	import { checkoutApi } from '@/api/endpoints/checkout'
4	
5	export interface CartItem {
6	  session_id: string
7	  session_title: string
8	  unit_price: number
9	  quantity: number
10	}
11	
12	export interface AppliedPromotion {
13	  promotion_id: string
14	  promotion_name: string
15	  promotion_type: string
16	  discount_amount: number
17	  explanation: string  // "Applied 'Buy-One-Get-One' because you have 2 workshops"
18	}
19	
20	export interface BestOffer {
21	  subtotal: number
22	  discount_total: number
23	  total: number
24	  applied_promotions: AppliedPromotion[]
25	}
26	
27	export interface Order {
28	  id: string
29	  learner_id: string
30	  status: 'pending' | 'paid' | 'cancelled' | 'refunded'
31	  subtotal: number
32	  discount_total: number
33	  total: number
34	  currency: string
35	  applied_promotions: AppliedPromotion[]
36	  items: CartItem[]
37	  created_at: string
38	  paid_at: string | null
39	  expires_at: string
40	}
41	
42	export const useCheckoutStore = defineStore('checkout', () => {
43	  const cartId = ref<string | null>(null)
44	  const cartItems = ref<CartItem[]>([])
45	  const bestOffer = ref<BestOffer | null>(null)
46	  const order = ref<Order | null>(null)
47	  const loading = ref(false)
48	  const bestOfferLoading = ref(false)
49	
50	  async function createCart(items: { session_id: string; quantity: number }[]) {
51	    loading.value = true
52	    try {
53	      const res = await checkoutApi.createCart(items)
54	      cartId.value = res.id
55	      cartItems.value = res.items
56	      // Immediately calculate best offer after cart creation
57	      await fetchBestOffer(res.id)
58	      return res
59	    } finally {
60	      loading.value = false
61	    }
62	  }
63	
64	  async function applyPromo(code: string) {
65	    if (!cartId.value) return
66	    bestOfferLoading.value = true
67	    try {
68	      await checkoutApi.applyPromo(cartId.value, code)
69	      await fetchBestOffer(cartId.value)
70	    } finally {
71	      bestOfferLoading.value = false
72	    }
73	  }
74	
75	  async function fetchBestOffer(id?: string) {
76	    const cid = id ?? cartId.value
77	    if (!cid) return
78	    bestOfferLoading.value = true
79	    try {
80	      bestOffer.value = await checkoutApi.getBestOffer(cid)
81	    } finally {
82	      bestOfferLoading.value = false
83	    }
84	  }
85	
86	  async function confirmCart() {
87	    if (!cartId.value) throw new Error('No active cart')
88	    loading.value = true
89	    try {
90	      order.value = await checkoutApi.confirmCart(cartId.value)
91	      return order.value
92	    } finally {
93	      loading.value = false
94	    }
95	  }
96	
97	  async function fetchOrder(id: string) {
98	    order.value = await checkoutApi.getOrder(id)
99	    return order.value
100	  }
101	
102	  async function cancelOrder(id: string) {
103	    order.value = await checkoutApi.cancelOrder(id)
104	    return order.value
105	  }
106	
107	  function clearCart() {
108	    cartId.value = null
109	    cartItems.value = []
110	    bestOffer.value = null
111	  }
112	
113	  return {
114	    cartId, cartItems, bestOffer, order, loading, bestOfferLoading,
115	    createCart, applyPromo, fetchBestOffer, confirmCart, fetchOrder, cancelOrder, clearCart,
116	  }
117	})
